class Solution {
public:
    long long smallestNumber(long long num) {
        string s = to_string(abs(num));
        sort(s.begin(), s.end());
        if (s[0] == '0') {
            for (int i = 1; i < s.size(); i++) {
                if (s[i] != '0') {
                    swap(s[0], s[i]);
                    break;
                }
            }
        }
        return (num < 0) ? -stoll(s) : stoll(s);
    }
};
```
